def simulate_cascade(grid_with_capacities, failed_edge, current_flows):
    rerouted_flows = reroute_flow(grid_with_capacities, failed_edge, current_flows)
    newly_overloaded = [
        edge for edge, flow in rerouted_flows.items()
        if flow > grid_with_capacities[edge]["capacity"]
    ]
    if not newly_overloaded:
        return {"cascade_stopped": True, "affected_edges": [failed_edge]}
    return simulate_cascade(grid_with_capacities, newly_overloaded[0], rerouted_flows)
